  8→  MoreVertical,
  9→  Paperclip,
 10→  Phone,
 11→  Video,
 12→  Smile,
 13→  Check,
 14→  CheckCheck,
 15→  Image as ImageIcon,
 16→  X
 17→} from 'lucide-react';
 18→import PageHeader from '../components/layout/PageHeader';
 19→
 20→interface MessagesProps {
 21→  onBack: () => void;
 22→  user: { name: string; plan: string; credits: number } | null;
 23→}
 24→
 25→interface Message {
 26→  id: string;
 27→  content: string;
 28→  timestamp: string;
 29→  sender: 'me' | 'them';
 30→  read: boolean;
 31→}
 32→
 33→interface Conversation {
 34→  id: string;
 35→  name: string;
 36→  avatar: string;
 37→  role: string;
 38→  lastMessage: string;
 39→  timestamp: string;
 40→  unread: number;
 41→  online: boolean;
 42→  messages: Message[];
 43→  category: 'all' | 'support';
 44→}
 45→
