 87→      { id: 'm4', content: 'Merci pour l\'info. Nous avons identifie un bug sur les exports depassant 500 lignes. Un correctif est en cours de deploiement.', timestamp: 'Hier 14:30', sender: 'them', read: true },
 88→      { id: 'm5', content: 'D\'accord, merci pour la reactivite.', timestamp: 'Hier 14:35', sender: 'me', read: true },
