122→      { id: 'm3', content: 'Parfait, tiens-moi au courant.', timestamp: 'Lun 10:00', sender: 'me', read: true },
123→      { id: 'm4', content: 'Les articles optimises AEO sont publies. On surveille les metrics.', timestamp: 'Lun 16:30', sender: 'them', read: true },
124→    ]
