126→  {
127→    id: 'conv-5',
128→    name: 'Thomas Durand',
129→    avatar: 'TD',
130→    role: 'Directeur Technique',
131→    lastMessage: 'L\'API v2 est en staging, prets pour les tests demain ?',
132→    timestamp: 'Dim',
133→    unread: 0,
134→    online: true,
135→    category: 'all',
136→    messages: [
137→      { id: 'm1', content: 'Thomas, comment avance l\'integration de l\'API v2 ?', timestamp: 'Dim 14:00', sender: 'me', read: true },
138→      { id: 'm2', content: 'On vient de finir les endpoints principaux. Le rate limiting est aussi en place.', timestamp: 'Dim 14:20', sender: 'them', read: true },
