142→  {
143→    id: 'conv-6',
144→    name: 'Support Facturation',
145→    avatar: 'SF',
146→    role: 'Service Comptabilite',
147→    lastMessage: 'Votre facture de janvier est disponible dans votre espace.',
148→    timestamp: '08/01',
149→    unread: 0,
150→    online: false,
151→    category: 'support',
152→    messages: [
153→      { id: 'm1', content: 'Bonjour, pourriez-vous me renvoyer la facture de decembre ?', timestamp: '07/01 10:00', sender: 'me', read: true },
154→      { id: 'm2', content: 'Bien sur, je vous la renvoie par email. Vous devriez la recevoir dans quelques minutes.', timestamp: '07/01 10:15', sender: 'them', read: true },
155→      { id: 'm3', content: 'Votre facture de janvier est disponible dans votre espace.', timestamp: '08/01 09:00', sender: 'them', read: true },
156→    ]
157→  }
158→];
159→
160→// ---------------------------------------------------------------------------
161→// COMPONENT
162→// ---------------------------------------------------------------------------
163→
164→const Messages: React.FC<MessagesProps> = ({ onBack, user }) => {
165→  const [conversations] = useState<Conversation[]>(DEMO_CONVERSATIONS);
166→  const [activeConversationId, setActiveConversationId] = useState<string>('conv-1');
167→  const [searchQuery, setSearchQuery] = useState('');
168→  const [filterTab, setFilterTab] = useState<'all' | 'unread' | 'support'>('all');
169→  const [messageInput, setMessageInput] = useState('');
170→  const [showMobileThread, setShowMobileThread] = useState(false);
171→  const [isTyping, setIsTyping] = useState(false);
172→  const [showEmojiHint, setShowEmojiHint] = useState(false);
173→
174→  const messagesEndRef = useRef<HTMLDivElement>(null);
175→  const inputRef = useRef<HTMLInputElement>(null);
176→
177→  const activeConversation = conversations.find(c => c.id === activeConversationId) || conversations[0];
178→
179→  const totalUnread = conversations.reduce((sum, c) => sum + c.unread, 0);
180→
181→  // Filter conversations
182→  const filteredConversations = conversations.filter(c => {
183→    const matchesSearch =
184→      c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
185→      c.lastMessage.toLowerCase().includes(searchQuery.toLowerCase());
186→
187→    if (filterTab === 'unread') return matchesSearch && c.unread > 0;
188→    if (filterTab === 'support') return matchesSearch && c.category === 'support';
189→    return matchesSearch;
190→  });
191→
192→  // Scroll to bottom on conversation change
193→  useEffect(() => {
194→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
195→  }, [activeConversationId, activeConversation.messages.length]);
196→
197→  // Simulate typing indicator when switching conversations
198→  useEffect(() => {
199→    if (activeConversation.online) {
200→      const timer = setTimeout(() => {
201→        setIsTyping(true);
202→        const stop = setTimeout(() => setIsTyping(false), 2500);
203→        return () => clearTimeout(stop);
204→      }, 3000);
205→      return () => clearTimeout(timer);
206→    }
207→    setIsTyping(false);
208→  }, [activeConversationId, activeConversation.online]);
209→
210→  const handleSelectConversation = (id: string) => {
211→    setActiveConversationId(id);
212→    setShowMobileThread(true);
213→  };
214→
215→  const handleSendMessage = () => {
216→    if (!messageInput.trim()) return;
217→    // In a real app this would send to backend; here we just clear input
218→    setMessageInput('');
219→    inputRef.current?.focus();
220→  };
221→
222→  const handleKeyDown = (e: React.KeyboardEvent) => {
223→    if (e.key === 'Enter' && !e.shiftKey) {
224→      e.preventDefault();
225→      handleSendMessage();
226→    }
227→  };
228→
229→  // ---------------------------------------------------------------------------
230→  // SUB-COMPONENTS
231→  // ---------------------------------------------------------------------------
232→
233→  const ConversationItem = ({ conv }: { conv: Conversation }) => {
234→    const isActive = conv.id === activeConversationId;
235→    return (
236→      <button
237→        onClick={() => handleSelectConversation(conv.id)}
238→        className={`w-full flex items-start gap-3 p-4 transition-all text-left rounded-xl group ${
239→          isActive
240→            ? 'bg-purple-500/10 border border-purple-500/20'
241→            : 'hover:bg-white/[0.03] border border-transparent'
242→        }`}
243→      >
244→        {/* Avatar */}
245→        <div className="relative flex-shrink-0">
246→          <div
247→            className={`w-11 h-11 rounded-full flex items-center justify-center text-sm font-bold ${
248→              isActive
249→                ? 'bg-purple-500/20 text-purple-300 border border-purple-500/30'
250→                : 'bg-white/[0.06] text-gray-300 border border-white/[0.06]'
251→            }`}
252→          >
253→            {conv.avatar}
254→          </div>
255→          {conv.online && (
256→            <span className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-green-500 rounded-full border-2 border-[var(--bg-surface)]" />
257→          )}
258→        </div>
259→
260→        {/* Text */}
261→        <div className="flex-1 min-w-0">
262→          <div className="flex justify-between items-center mb-0.5">
263→            <span className={`text-sm font-semibold truncate ${isActive ? 'text-white' : 'text-gray-200'}`}>
264→              {conv.name}
265→            </span>
266→            <span className="text-[11px] text-gray-500 flex-shrink-0 ml-2">{conv.timestamp}</span>
267→          </div>
268→          <p className="text-xs text-gray-500 truncate leading-relaxed">{conv.lastMessage}</p>
269→        </div>
270→
271→        {/* Unread badge */}
272→        {conv.unread > 0 && (
273→          <span className="flex-shrink-0 mt-1 w-5 h-5 flex items-center justify-center bg-purple-500 text-white text-[10px] font-bold rounded-full">
274→            {conv.unread}
275→          </span>
276→        )}
277→      </button>
278→    );
279→  };
280→
281→  const MessageBubble = ({ msg, isLast }: { msg: Message; isLast: boolean }) => {
282→    const isMine = msg.sender === 'me';
283→    return (
284→      <div className={`flex ${isMine ? 'justify-end' : 'justify-start'} mb-2 group`}>
285→        <div className={`max-w-[75%] ${isMine ? 'order-2' : 'order-1'}`}>
286→          <div
287→            className={`px-4 py-2.5 text-sm leading-relaxed ${
288→              isMine
289→                ? 'bg-purple-500/20 text-purple-100 rounded-2xl rounded-br-md border border-purple-500/20'
290→                : 'bg-white/[0.05] text-gray-300 rounded-2xl rounded-bl-md border border-[var(--border-subtle)]'
291→            }`}
292→          >
293→            {msg.content}
294→          </div>
295→          <div className={`flex items-center gap-1 mt-1 ${isMine ? 'justify-end' : 'justify-start'}`}>
296→            <span className="text-[10px] text-[var(--text-disabled)]">{msg.timestamp}</span>
297→            {isMine && (
298→              msg.read
299→                ? <CheckCheck size={12} className="text-purple-400" />
300→                : <Check size={12} className="text-[var(--text-disabled)]" />
301→            )}
302→          </div>
303→        </div>
304→      </div>
305→    );
306→  };
307→
308→  // ---------------------------------------------------------------------------
309→  // RENDER: Conversation List Panel
310→  // ---------------------------------------------------------------------------
311→
312→  const ConversationListPanel = (
313→    <div
314→      className={`flex flex-col h-full ${
315→        showMobileThread ? 'hidden lg:flex' : 'flex'
316→      } lg:w-[380px] lg:min-w-[340px] lg:border-r lg:border-[var(--border-subtle)]`}
317→    >
318→      {/* Search */}
319→      <div className="p-4 border-b border-[var(--border-subtle)]">
320→        <div className="relative">
321→          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
322→          <input
323→            type="text"
324→            placeholder="Rechercher une conversation..."
325→            value={searchQuery}
326→            onChange={e => setSearchQuery(e.target.value)}
327→            className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl pl-10 pr-4 py-2.5 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-purple-500/40 transition-colors"
328→          />
329→        </div>
330→
331→        {/* Filter tabs */}
332→        <div className="flex gap-2 mt-3">
333→          {([
334→            { key: 'all', label: 'Tous' },
335→            { key: 'unread', label: 'Non lus' },
336→            { key: 'support', label: 'Support' },
337→          ] as const).map(tab => (
338→            <button
339→              key={tab.key}
340→              onClick={() => setFilterTab(tab.key)}
341→              className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${
342→                filterTab === tab.key
343→                  ? 'bg-purple-500/15 text-purple-300 border border-purple-500/25'
344→                  : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:text-gray-300'
345→              }`}
346→            >
347→              {tab.label}
348→              {tab.key === 'unread' && totalUnread > 0 && (
349→                <span className="ml-1.5 text-[10px] bg-purple-500 text-white px-1.5 py-0.5 rounded-full">{totalUnread}</span>
350→              )}
351→            </button>
352→          ))}
353→        </div>
354→      </div>
355→
356→      {/* Conversation list */}
357→      <div className="flex-1 overflow-y-auto px-2 py-2 space-y-1 custom-scrollbar">
358→        {filteredConversations.length === 0 ? (
359→          <div className="flex flex-col items-center justify-center py-16 text-center">
360→            <MessageSquare size={32} className="text-[var(--text-disabled)] mb-3" />
361→            <p className="text-sm text-gray-500">Aucune conversation trouvee</p>
362→          </div>
363→        ) : (
364→          filteredConversations.map(conv => (
365→            <ConversationItem key={conv.id} conv={conv} />
366→          ))
367→        )}
368→      </div>
369→    </div>
370→  );
371→
372→  // ---------------------------------------------------------------------------
373→  // RENDER: Message Thread Panel
374→  // ---------------------------------------------------------------------------
375→
376→  const MessageThreadPanel = (
377→    <div
378→      className={`flex flex-col flex-1 h-full ${
379→        showMobileThread ? 'flex' : 'hidden lg:flex'
380→      }`}
381→    >
382→      {/* Thread header */}
383→      <div className="flex items-center justify-between px-5 py-4 border-b border-[var(--border-subtle)]">
384→        <div className="flex items-center gap-3">
385→          {/* Mobile back */}
386→          <button
387→            onClick={() => setShowMobileThread(false)}
388→            className="lg:hidden p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-400 transition-colors mr-1"
389→          >
390→            <ArrowLeft size={18} />
391→          </button>
392→          {/* Avatar */}
393→          <div className="relative">
394→            <div className="w-10 h-10 rounded-full bg-purple-500/15 border border-purple-500/25 flex items-center justify-center text-sm font-bold text-purple-300">
395→              {activeConversation.avatar}
396→            </div>
397→            {activeConversation.online && (
398→              <span className="absolute -bottom-0.5 -right-0.5 w-3 h-3 bg-green-500 rounded-full border-2 border-[var(--bg-surface)]" />
399→            )}
400→          </div>
401→          <div>
402→            <h3 className="text-sm font-semibold text-white">{activeConversation.name}</h3>
403→            <p className="text-[11px] text-gray-500">
404→              {activeConversation.online ? (
405→                <span className="text-green-400 flex items-center gap-1">
406→                  <Circle size={6} className="fill-green-400" /> En ligne
407→                </span>
408→              ) : (
409→                'Hors ligne'
410→              )}
411→              {' — '}{activeConversation.role}
412→            </p>
413→          </div>
414→        </div>
415→        <div className="flex items-center gap-1">
416→          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors hidden sm:block">
417→            <Phone size={16} />
418→          </button>
419→          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors hidden sm:block">
420→            <Video size={16} />
421→          </button>
422→          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors">
423→            <MoreVertical size={16} />
424→          </button>
425→        </div>
426→      </div>
427→
428→      {/* Messages */}
429→      <div className="flex-1 overflow-y-auto px-5 py-5 space-y-1 custom-scrollbar">
430→        {/* Date separator */}
431→        <div className="flex items-center justify-center mb-5">
432→          <span className="text-[10px] text-[var(--text-disabled)] bg-white/[0.03] border border-[var(--border-subtle)] px-3 py-1 rounded-full">
433→            Aujourd'hui
434→          </span>
435→        </div>
436→
437→        {activeConversation.messages.map((msg, idx) => (
438→          <MessageBubble
439→            key={msg.id}
440→            msg={msg}
441→            isLast={idx === activeConversation.messages.length - 1}
442→          />
443→        ))}
444→
445→        {/* Typing indicator */}
446→        {isTyping && (
447→          <div className="flex justify-start mb-2">
448→            <div className="bg-white/[0.05] border border-[var(--border-subtle)] rounded-2xl rounded-bl-md px-4 py-3 flex items-center gap-1.5">
449→              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
450→              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
451→              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
452→            </div>
453→          </div>
454→        )}
455→
456→        <div ref={messagesEndRef} />
457→      </div>
458→
459→      {/* Input bar */}
460→      <div className="px-5 py-4 border-t border-[var(--border-subtle)]">
461→        <div className="flex items-center gap-2 bg-white/[0.03] border border-white/[0.06] rounded-2xl px-4 py-2 focus-within:border-purple-500/40 transition-colors">
462→          <button
463→            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
464→            title="Joindre un fichier"
465→          >
466→            <Paperclip size={18} />
467→          </button>
468→          <button
469→            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
470→            title="Image"
471→          >
472→            <ImageIcon size={18} />
473→          </button>
474→          <input
475→            ref={inputRef}
476→            type="text"
477→            placeholder="Ecrire un message..."
478→            value={messageInput}
479→            onChange={e => setMessageInput(e.target.value)}
480→            onKeyDown={handleKeyDown}
481→            className="flex-1 bg-transparent text-sm text-white placeholder-gray-500 focus:outline-none py-1"
482→          />
483→          <button
484→            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
485→            title="Emoji"
486→            onClick={() => setShowEmojiHint(prev => !prev)}
487→          >
488→            <Smile size={18} />
489→          </button>
490→          <button
491→            onClick={handleSendMessage}
492→            disabled={!messageInput.trim()}
493→            className={`p-2 rounded-xl flex-shrink-0 transition-all ${
494→              messageInput.trim()
495→                ? 'bg-purple-500 hover:bg-purple-600 text-white shadow-lg shadow-purple-500/20'
496→                : 'bg-white/[0.03] text-[var(--text-disabled)] cursor-not-allowed'
497→            }`}
498→            title="Envoyer"
499→          >
500→            <Send size={16} />
501→          </button>
502→        </div>
503→        {showEmojiHint && (
